import { motion } from 'framer-motion';
import { cn } from '../../utils';

type BodyZone = 'head' | 'chest' | 'gut' | 'upper' | 'lower' | 'core' | 'full' | null;

interface BodyGraphicProps {
  highlightZone?: BodyZone;
  className?: string;
  size?: number;
}

const zoneColors: Record<string, string> = {
  head:  '#EF4444',
  chest: '#F97316',
  gut:   '#EF4444',
  upper: '#F97316',
  lower: '#EF4444',
  core:  '#F97316',
  full:  '#EF4444',
};

export function BodyGraphic({ highlightZone, className, size = 160 }: BodyGraphicProps) {
  const color = highlightZone ? zoneColors[highlightZone] : 'transparent';
  const isHead    = highlightZone === 'head'  || highlightZone === 'full';
  const isChest   = highlightZone === 'chest' || highlightZone === 'upper' || highlightZone === 'full';
  const isGut     = highlightZone === 'gut'   || highlightZone === 'core'  || highlightZone === 'full';
  const isLower   = highlightZone === 'lower' || highlightZone === 'full';
  const isUpper   = highlightZone === 'upper' || highlightZone === 'full';

  const pulseAnim = {
    initial: { opacity: 0.6 },
    animate: { opacity: [0.6, 1, 0.6] },
    transition: { duration: 1.8, repeat: Infinity, ease: 'easeInOut' },
  };

  return (
    <div className={cn('flex items-center justify-center', className)}>
      <svg
        width={size}
        height={size * 1.7}
        viewBox="0 0 120 200"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Body silhouette base */}
        <ellipse cx="60" cy="30" rx="18" ry="20" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M42 58 Q60 52 78 58 L82 120 Q60 128 38 120 Z" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M42 60 L28 100 Q24 108 32 110 L40 90" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M78 60 L92 100 Q96 108 88 110 L80 90" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M46 120 L40 175 Q42 182 52 180 L56 140" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M74 120 L80 175 Q78 182 68 180 L64 140" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>

        {/* HEAD highlight */}
        {isHead && (
          <motion.ellipse cx="60" cy="30" rx="18" ry="20" fill={color} fillOpacity="0.5"
            {...pulseAnim} />
        )}
        {/* CHEST / UPPER highlight */}
        {isChest && (
          <motion.path d="M44 58 Q60 52 76 58 L78 90 Q60 96 42 90 Z" fill={color} fillOpacity="0.45"
            {...pulseAnim} />
        )}
        {/* GUT / CORE highlight */}
        {isGut && (
          <motion.path d="M42 90 Q60 96 78 90 L80 118 Q60 126 40 118 Z" fill={color} fillOpacity="0.5"
            {...pulseAnim} />
        )}
        {/* UPPER BODY — shoulders + arms */}
        {isUpper && (
          <>
            <motion.path d="M42 60 L28 100 Q24 108 32 110 L40 90" fill={color} fillOpacity="0.4"
              {...pulseAnim} />
            <motion.path d="M78 60 L92 100 Q96 108 88 110 L80 90" fill={color} fillOpacity="0.4"
              {...pulseAnim} />
          </>
        )}
        {/* LOWER BODY highlight */}
        {isLower && (
          <>
            <motion.path d="M46 120 L40 175 Q42 182 52 180 L56 140" fill={color} fillOpacity="0.5"
              {...pulseAnim} />
            <motion.path d="M74 120 L80 175 Q78 182 68 180 L64 140" fill={color} fillOpacity="0.5"
              {...pulseAnim} />
          </>
        )}

        {/* Pulse ring on active zone */}
        {highlightZone && (
          <motion.circle
            cx="60"
            cy={isHead ? 30 : isGut || isLower ? 130 : 75}
            r="8"
            stroke={color}
            strokeWidth="2"
            fill="none"
            initial={{ scale: 0.5, opacity: 1 }}
            animate={{ scale: 2.5, opacity: 0 }}
            transition={{ duration: 1.5, repeat: Infinity, ease: 'easeOut' }}
          />
        )}

        {/* Spine line */}
        <line x1="60" y1="50" x2="60" y2="120" stroke="#2D9E8F" strokeWidth="0.8" strokeDasharray="3,3" opacity="0.4"/>
      </svg>
    </div>
  );
}

// ─── Nervous System Diagram ───────────────────────────────────────────────────
const NS_NODES = [
  { label: 'Sleep',    emoji: '😴', color: '#C2410C', bg: '#7C2D12', x: 54,  y: 44  },
  { label: 'Gut',      emoji: '🌿', color: '#B91C1C', bg: '#7F1D1D', x: 50,  y: 120 },
  { label: 'Mood',     emoji: '💙', color: '#C2410C', bg: '#7C2D12', x: 54,  y: 196 },
  { label: 'Muscles',  emoji: '💪', color: '#B91C1C', bg: '#7F1D1D', x: 246, y: 44  },
  { label: 'Hormones', emoji: '⚗️', color: '#C2410C', bg: '#7C2D12', x: 246, y: 196 },
];

// Line from ellipse edge toward each node
const NS_LINES = [
  { x1: 122, y1: 86,  x2: 86,  y2: 58  },
  { x1: 114, y1: 120, x2: 82,  y2: 120 },
  { x1: 122, y1: 152, x2: 86,  y2: 182 },
  { x1: 178, y1: 86,  x2: 214, y2: 58  },
  { x1: 178, y1: 152, x2: 214, y2: 182 },
];

export function NervousSystemDiagram({ className }: { className?: string }) {
  return (
    <div className={cn('relative w-full', className)}>
      <svg viewBox="0 0 300 240" className="w-full" style={{ height: 240 }}>
        {/* Connecting lines */}
        {NS_LINES.map((l, i) => (
          <motion.line
            key={i} x1={l.x1} y1={l.y1} x2={l.x2} y2={l.y2}
            stroke="rgba(255,255,255,0.35)" strokeWidth="1.5"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }}
            transition={{ delay: i * 0.12 + 0.2, duration: 0.4 }}
          />
        ))}

        {/* Central ellipse */}
        <motion.ellipse
          cx="150" cy="120" rx="46" ry="60"
          fill="#0B3330" stroke="rgba(255,255,255,0.2)" strokeWidth="1.5"
          animate={{ opacity: [0.88, 1, 0.88] }}
          transition={{ duration: 3.5, repeat: Infinity, ease: 'easeInOut' }}
        />
        {/* Brain emoji in center */}
        <text x="150" y="112" textAnchor="middle" fontSize="22">🧠</text>
        <text x="150" y="133" textAnchor="middle" fill="white" fontSize="11" fontWeight="700" fontFamily="Georgia, serif">Nervous</text>
        <text x="150" y="148" textAnchor="middle" fill="rgba(180,230,220,0.9)" fontSize="10" fontFamily="sans-serif">System</text>

        {/* Satellite nodes */}
        {NS_NODES.map((n, i) => (
          <motion.g
            key={n.label}
            initial={{ opacity: 0, scale: 0.4 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: i * 0.12 + 0.35, duration: 0.35, type: 'spring', stiffness: 220 }}
            style={{ transformOrigin: `${n.x}px ${n.y}px` }}
          >
            {/* Solid filled circle — fully opaque, readable */}
            <circle cx={n.x} cy={n.y} r="30" fill="rgba(0,0,0,0.35)" />
            <circle cx={n.x} cy={n.y} r="28" fill={n.bg} opacity="0.85" />
            <circle cx={n.x} cy={n.y} r="28" fill="none" stroke="rgba(255,255,255,0.25)" strokeWidth="1" />
            {/* Emoji */}
            <text x={n.x} y={n.y - 6} textAnchor="middle" fontSize="14">{n.emoji}</text>
            {/* White label — always readable */}
            <text x={n.x} y={n.y + 12} textAnchor="middle" fill="white" fontSize="9.5" fontWeight="700" fontFamily="sans-serif">
              {n.label}
            </text>
          </motion.g>
        ))}
      </svg>
    </div>
  );
}

